import { ProcessorRegistry } from '../../src/core/registry';
import { createBuiltInProcessors, DEFAULT_PROCESSOR_CONFIGS } from '../../src/processors';
import { RuleEngine } from '../../src/rules/ruleEngine';
import { BUILT_IN_RULES } from '../../src/rules/builtInRules';
import { LruCache } from '../../src/storage/cache';

describe('Pipeline', () => {
  it('executes enabled processors and returns cache hits on repeated requests', async () => {
    const metrics = new MetricsCollector();
    const ruleEngine = new RuleEngine(metrics, new StructuredLogger('pipeline-rules'));
    ruleEngine.setRules(BUILT_IN_RULES);
    const registry = new ProcessorRegistry(createBuiltInProcessors(ruleEngine), new StructuredLogger('pipeline-registry'));
    registry.loadRuntimeConfigs(DEFAULT_PROCESSOR_CONFIGS);
    const pipeline = new Pipeline(
      registry,
      new LruCache(50),
      metrics,
      new StructuredLogger('pipeline'),
    );

    const first = await pipeline.execute({
      content: 'Reach me at jane@example.com about launch planning',
    });
    const second = await pipeline.execute({
      content: 'Reach me at jane@example.com about launch planning',
    });

    expect(first.cacheStatus).toBe('miss');
    expect(first.processorsRun).toEqual(['anonymizer', 'keywordExtractor', 'metadataExtractor']);
    expect(first.result.anonymized).toContain('[EMAIL_1]');
    expect(first.result.keywords?.keywords.length).toBeGreaterThan(0);
    expect(second.cacheStatus).toBe('hit');
  });
});
"
}

