  "output": "import { ConfigValidationResult, Processor, ProcessorRunResult, ProcessorRuntimeConfig } from '../types';
import { tokenizeWords } from '../utils/tokenize';
import { isStopWord } from '../utils/stopWords';
import { createValidationResult } from '../utils/validation';

export class KeywordExtractorProcessor implements Processor {
  readonly definition = {
    id: 'keywordExtractor',
    name: 'Keyword Extractor',
    description: 'Extracts frequency-ranked keywords from the original note content.',
    supportsOverrides: true,
    dependencyIds: [],
  };

  validate(config: ProcessorRuntimeConfig): ConfigValidationResult {
    const errors = [];
    const maxKeywords = Number(config.options.maxKeywords ?? 8);
    if (!Number.isFinite(maxKeywords) || maxKeywords <= 0) {
      errors.push({
        path: `${config.id}.options.maxKeywords`,
        message: 'maxKeywords must be a positive number.',
      });
    }

    return createValidationResult(errors);
  }

  async process(context: Parameters<Processor['process']>[0], config: ProcessorRuntimeConfig): Promise<ProcessorRunResult> {
    const maxKeywords = Number(config.options.maxKeywords ?? 8);
    const minimumTokenLength = Number(config.options.minTokenLength ?? 3);
    const frequency = new Map<string, number>();

    for (const token of tokenizeWords(context.originalContent)) {
      if (token.length < minimumTokenLength || isStopWord(token)) {
        continue;
      }

      frequency.set(token, (frequency.get(token) ?? 0) + 1);
    }

    const topWords = Array.from(frequency.entries())
      .sort((left, right) => {
        if (right[1] !== left[1]) {
          return right[1] - left[1];
        }

        return left[0].localeCompare(right[0]);
      })
      .slice(0, maxKeywords)
      .map(([word, count]) => ({
        word,
        frequency: count,
      }));

    return {
      output: {
        keywords: {
          keywords: topWords.map((entry) => entry.word),
          topWords,
        },
      },
    };
  }
}
"
}

