export class MetadataExtractorProcessor implements Processor {
  readonly definition = {
    id: 'metadataExtractor',
    name: 'Metadata Extractor',
    description: 'Computes simple note metadata such as counts and reading time.',
    supportsOverrides: true,
    dependencyIds: [],
  };

  validate(config: ProcessorRuntimeConfig): ConfigValidationResult {
    const errors = [];
    const wordsPerMinute = Number(config.options.wordsPerMinute ?? 200);
    if (!Number.isFinite(wordsPerMinute) || wordsPerMinute <= 0) {
      errors.push({
        path: `${config.id}.options.wordsPerMinute`,
        message: 'wordsPerMinute must be a positive number.',
      });
    }

    return createValidationResult(errors);
  }

  async process(context: Parameters<Processor['process']>[0], config: ProcessorRuntimeConfig): Promise<ProcessorRunResult> {
    const wordsPerMinute = Number(config.options.wordsPerMinute ?? 200);
    const wordCount = tokenizeWords(context.originalContent).length;

    return {
      output: {
        metadata: {
          wordCount,
          charCount: context.originalContent.length,
          readingTimeMinutes: wordCount === 0 ? 0 : Math.ceil(wordCount / wordsPerMinute),
        },
      },
    };
  }
}
