        }

        // Build the remaining queue + new dynamic processors and re-sort topologically
        const remaining = processorQueue.slice(queueIndex);
        const dynamicResolved: ResolvedProcessor[] = newDynamicProcessors.map((dp) => ({
          processor: dp.processor,
          config: dp.config,
        }));

        // Combine remaining + dynamic, re-sort
        const combined = [...remaining, ...dynamicResolved];
        try {
          const sorted = ProcessorRegistry.topologicalSort(combined, allConfigsSeen);
          // Replace the remaining queue with the sorted result
          processorQueue.splice(queueIndex, processorQueue.length - queueIndex, ...sorted);
        } catch (err) {
          // If topological sort fails for dynamic processors, report error and skip them
          const message = err instanceof Error ? err.message : String(err);
          errors.push(`dynamic-registration: ${message}`);
          // Add non-dynamic ones back without the problematic ones
          processorQueue.splice(queueIndex, processorQueue.length - queueIndex, ...remaining);
        }
      }

      if (queueIndex >= processorQueue.length) break;

      const { processor, config } = processorQueue[queueIndex];
      queueIndex++;

      // Check if any dependency was skipped - if so, handle accordingly
      const deps = config.dependencyIds ?? [];
      let dependencySkipped = false;
      for (const depId of deps) {
        if (skippedSet.has(depId)) {
          dependencySkipped = true;
          break;
        }
      }

      if (dependencySkipped) {
        if (config.condition) {
          // Has a condition - skip it
          skippedProcessors.push(processor.definition.id);
          skippedSet.add(processor.definition.id);
          continue;
        } else {
          // No condition - fail with error
          const message = `Processor "${processor.definition.id}" depends on a skipped processor`;
          errors.push(`${config.id}: ${message}`);
          this.logger.error('processor-failed', {
            processorId: processor.definition.id,
            message,
          });
          continue;
        }
      }

      // Evaluate condition if present
      if (config.condition) {
        let conditionResult: boolean;
        try {
          conditionResult = await config.condition(context);
        } catch (err) {
          const message = err instanceof Error ? err.message : String(err);
          errors.push(`${config.id}: condition evaluation failed: ${message}`);
          skippedProcessors.push(processor.definition.id);
          skippedSet.add(processor.definition.id);
          continue;
        }

        if (!conditionResult) {
          skippedProcessors.push(processor.definition.id);
          skippedSet.add(processor.definition.id);
          continue;
        }
      }

      const validation = processor.validate(config);
      if (!validation.valid) {
        errors.push(...validation.errors.map((entry) => `${config.id}: ${entry.message}`));
        continue;
      }

      warnings.push(...validation.warnings.map((warning) => `${config.id}: ${warning}`));
      const runStarted = performance.now();

      try {
        const run = await processor.process(context, config);
        processorsRun.push(processor.definition.id);

        // Compute raw output
        let rawOutput: unknown = run.output ?? {};

        // Apply output transform if present
        if (config.outputTransform) {
          rawOutput = await config.outputTransform(rawOutput, context);
        }

        // Store in outputs under the processor's ID
        outputs[processor.definition.id] = rawOutput;

        // Also merge into context.result for backwards compatibility
        if (rawOutput && typeof rawOutput === 'object') {
          Object.assign(context.result, rawOutput);
        }

        if (run.nextContent !== undefined) {
          context.workingContent = run.nextContent;
          context.result.workingCopy = run.nextContent;
        }
        if (run.errors) {
          errors.push(...run.errors.map((message) => `${config.id}: ${message}`));
        }
        if (run.warnings) {
          warnings.push(...run.warnings.map((message) => `${config.id}: ${message}`));
        }
        this.metrics.recordProcessorRun(processor.definition.id, performance.now() - runStarted, true);
      } catch (error) {
        this.metrics.recordProcessorRun(processor.definition.id, performance.now() - runStarted, false);
        const message = error instanceof Error ? error.message : String(error);
        errors.push(`${config.id}: ${message}`);
        context.lastError = error instanceof Error ? error : new Error(message);
        this.logger.error('processor-failed', {
          processorId: processor.definition.id,
          message,
        });
      }

      // After each processor, check for any newly registered dynamic processors
      if (pendingDynamicProcessors.length > 0) {
        const newDynamicProcessors = [...pendingDynamicProcessors];
        pendingDynamicProcessors.length = 0;

        for (const dp of newDynamicProcessors) {
          allConfigsSeen.set(dp.config.id, dp.config);
          dynamicProcessors.push(dp.config.id);
        }

        // Build the remaining queue + new dynamic processors and re-sort topologically
        const remaining = processorQueue.slice(queueIndex);
        const dynamicResolved: ResolvedProcessor[] = newDynamicProcessors.map((dp) => ({
          processor: dp.processor,
          config: dp.config,
        }));

        // Combine remaining + dynamic, re-sort
        const combined = [...remaining, ...dynamicResolved];
        try {
          const sorted = ProcessorRegistry.topologicalSort(combined, allConfigsSeen);
          // Replace the remaining queue with the sorted result
          processorQueue.splice(queueIndex, processorQueue.length - queueIndex, ...sorted);
        } catch (err) {
          // If topological sort fails for dynamic processors, report error and skip them
          const message = err instanceof Error ? err.message : String(err);
          errors.push(`dynamic-registration: ${message}`);
          processorQueue.splice(queueIndex, processorQueue.length - queueIndex, ...remaining);
        }
      }
    }

    const finishedAt = new Date().toISOString();
    const execution: PipelineExecutionResult = {
      cacheStatus: 'miss',
      processorsRun,
      result: clone(context.result),
      errors,
      warnings,
      startedAt,
      finishedAt,
      skippedProcessors: skippedProcessors.length > 0 ? skippedProcessors : [],
      dynamicProcessors: dynamicProcessors.length > 0 ? dynamicProcessors : [],
    };

    this.cache.set(cacheKey, clone(execution));
    return execution;
  }
}
