/**
 * Golden tests for Processor Dependency Ordering feature.
 *
 * Tests cover:
 * - Dependency Ordering (topological sort)
 * - Conditional Execution
 * - Output Transformation
 * - Runtime Processor Registration
 * - Integration & Regression
 */

import { ProcessorRegistry, ResolvedProcessor } from '../src/core/registry';
import { Pipeline } from '../src/core/pipeline';
import { MetricsCollector } from '../src/metrics/metrics';
import { StructuredLogger } from '../src/metrics/logger';
import { LruCache } from '../src/storage/cache';
import {
  Processor,
  ProcessorDefinition,
  ProcessorRuntimeConfig,
  ProcessorRunResult,
  ProcessingContext,
  ConfigValidationResult,
  PipelineExecutionResult,
} from '../src/types';

// ─── Helper: Create a simple test processor ────────────────────────────────────

function makeProcessor(
  id: string,
  deps: string[] = [],
  runFn?: (context: ProcessingContext, config: ProcessorRuntimeConfig) => Promise<ProcessorRunResult>,
): Processor {
  const definition: ProcessorDefinition = {
    id,
    name: id,
    description: `Test processor ${id}`,
    supportsOverrides: false,
    dependencyIds: deps,
  };

  return {
    definition,
    validate(_config: ProcessorRuntimeConfig): ConfigValidationResult {
      return { valid: true, errors: [], warnings: [] };
    },
    async process(context: ProcessingContext, config: ProcessorRuntimeConfig): Promise<ProcessorRunResult> {
      if (runFn) {
        return runFn(context, config);
      }
      return { output: { custom: { [`${id}_ran`]: true } } };
    },
  };
}

function makeConfig(
  id: string,
  order: number,
  deps: string[] = [],
  extra: Partial<ProcessorRuntimeConfig> = {},
): ProcessorRuntimeConfig {
  return {
    id,
    enabled: true,
    order,
    dependencyIds: deps,
    options: {},
    ...extra,
  };
}

function makePipeline(processors: Processor[], configs: ProcessorRuntimeConfig[]) {
  const registry = new ProcessorRegistry(processors, new StructuredLogger('test-registry'));
  registry.loadRuntimeConfigs(configs);
  return {
    registry,
    pipeline: new Pipeline(
      registry,
      new LruCache(50),
      new MetricsCollector(),
      new StructuredLogger('test-pipeline'),
    ),
  };
}

// ─── Helper: Topological sort helper for direct registry tests ─────────────────

function makeResolvedProcessors(
  items: Array<{ id: string; order: number; deps: string[] }>,
): ResolvedProcessor[] {
  return items.map(({ id, order, deps }) => ({
    processor: makeProcessor(id, deps),
    config: makeConfig(id, order, deps),
  }));
}

function makeAllConfigs(
  items: Array<{ id: string; order: number; deps: string[]; enabled?: boolean }>,
): Map<string, ProcessorRuntimeConfig> {
  const map = new Map<string, ProcessorRuntimeConfig>();
  for (const item of items) {
    map.set(item.id, {
      id: item.id,
      enabled: item.enabled ?? true,
      order: item.order,
      dependencyIds: item.deps,
      options: {},
    });
  }
  return map;
}

// ─── DEPENDENCY ORDERING TESTS ───────────────────────────────────────────────

describe('Dependency Ordering', () => {
  it('linear dependency chains are topologically sorted', () => {
    // A -> B -> C (C depends on B, B depends on A)
    const items = [
      { id: 'C', order: 30, deps: ['B'] },
      { id: 'A', order: 10, deps: [] },
      { id: 'B', order: 20, deps: ['A'] },
    ];
    const resolved = makeResolvedProcessors(items);
    const allConfigs = makeAllConfigs(items);

    const sorted = ProcessorRegistry.topologicalSort(resolved, allConfigs);
    const ids = sorted.map((r) => r.config.id);

    expect(ids.indexOf('A')).toBeLessThan(ids.indexOf('B'));
    expect(ids.indexOf('B')).toBeLessThan(ids.indexOf('C'));
  });

  it('circular dependencies are detected and rejected', () => {
    // A depends on B, B depends on A
    const items = [
      { id: 'A', order: 10, deps: ['B'] },
      { id: 'B', order: 20, deps: ['A'] },
    ];
    const resolved = makeResolvedProcessors(items);
    const allConfigs = makeAllConfigs(items);

    expect(() => ProcessorRegistry.topologicalSort(resolved, allConfigs)).toThrow(
      /[Cc]ircular/,
    );
  });

  it('missing dependencies are detected and rejected', () => {
    // A depends on X which doesn't exist
    const items = [{ id: 'A', order: 10, deps: ['X'] }];
    const resolved = makeResolvedProcessors(items);
    const allConfigs = makeAllConfigs(items); // X is not in allConfigs

    expect(() => ProcessorRegistry.topologicalSort(resolved, allConfigs)).toThrow(
      /missing/i,
    );
  });

  it('disabled dependencies are detected and rejected', () => {
    // A depends on B, B is disabled
    const allItems = [
      { id: 'A', order: 10, deps: ['B'], enabled: true },
      { id: 'B', order: 5, deps: [], enabled: false },
    ];
    const allConfigs = makeAllConfigs(allItems);

    // Only A is "resolved" (enabled), B is not in resolved
    const resolved = makeResolvedProcessors([{ id: 'A', order: 10, deps: ['B'] }]);

    expect(() => ProcessorRegistry.topologicalSort(resolved, allConfigs)).toThrow(
      /disabled/i,
    );
  });

  it('transitive dependencies are properly ordered', () => {
    // D depends on C, C depends on B, B depends on A
    const items = [
      { id: 'D', order: 40, deps: ['C'] },
      { id: 'C', order: 30, deps: ['B'] },
      { id: 'B', order: 20, deps: ['A'] },
      { id: 'A', order: 10, deps: [] },
    ];
    const resolved = makeResolvedProcessors(items);
    const allConfigs = makeAllConfigs(items);

    const sorted = ProcessorRegistry.topologicalSort(resolved, allConfigs);
    const ids = sorted.map((r) => r.config.id);

    expect(ids.indexOf('A')).toBeLessThan(ids.indexOf('B'));
    expect(ids.indexOf('B')).toBeLessThan(ids.indexOf('C'));
    expect(ids.indexOf('C')).toBeLessThan(ids.indexOf('D'));
  });

  it('diamond patterns are handled correctly', () => {
    // D depends on B and C, both depend on A
    const items = [
      { id: 'D', order: 40, deps: ['B', 'C'] },
      { id: 'C', order: 30, deps: ['A'] },
      { id: 'B', order: 20, deps: ['A'] },
      { id: 'A', order: 10, deps: [] },
    ];
    const resolved = makeResolvedProcessors(items);
    const allConfigs = makeAllConfigs(items);

    const sorted = ProcessorRegistry.topologicalSort(resolved, allConfigs);
    const ids = sorted.map((r) => r.config.id);

    expect(ids).toHaveLength(4);
    expect(ids.indexOf('A')).toBeLessThan(ids.indexOf('B'));
    expect(ids.indexOf('A')).toBeLessThan(ids.indexOf('C'));
    expect(ids.indexOf('B')).toBeLessThan(ids.indexOf('D'));
    expect(ids.indexOf('C')).toBeLessThan(ids.indexOf('D'));
  });

  it('self-dependencies are detected as circular', () => {
    const items = [{ id: 'A', order: 10, deps: ['A'] }];
    const resolved = makeResolvedProcessors(items);
    const allConfigs = makeAllConfigs(items);

    expect(() => ProcessorRegistry.topologicalSort(resolved, allConfigs)).toThrow(
      /[Cc]ircular|self/i,
    );
  });

  it('pipeline resolves processors in topological order', async () => {
    // B depends on A - A should run before B regardless of order field
    const executionOrder: string[] = [];

    const processorA = makeProcessor('A', [], async (ctx, _cfg) => {
      executionOrder.push('A');
      return { output: { custom: { aResult: 42 } } };
    });
    const processorB = makeProcessor('B', ['A'], async (ctx, _cfg) => {
      executionOrder.push('B');
      return { output: { custom: { bResult: (ctx.outputs['A'] as any)?.custom?.aResult } } };
    });

    const configs: ProcessorRuntimeConfig[] = [
      makeConfig('B', 10, ['A']), // B has lower order but depends on A
      makeConfig('A', 20, []),    // A has higher order
    ];

    const { pipeline } = makePipeline([processorA, processorB], configs);
    const result = await pipeline.execute({ content: 'test' });

    expect(executionOrder).toEqual(['A', 'B']);
    expect(result.processorsRun).toEqual(['A', 'B']);
  });
});

// ─── CONDITIONAL EXECUTION TESTS ─────────────────────────────────────────────

describe('Conditional Execution', () => {
  it('processor with passing condition executes normally', async () => {
    const processor = makeProcessor('conditional', [], async (_ctx, _cfg) => {
      return { output: { custom: { ran: true } } };
    });

    const config = makeConfig('conditional', 10, [], {
      condition: async (_ctx) => true,
    });

    const { pipeline } = makePipeline([processor], [config]);
    const result = await pipeline.execute({ content: 'hello' });

    expect(result.processorsRun).toContain('conditional');
    expect(result.skippedProcessors).not.toContain('conditional');
  });

  it('processor with failing condition is skipped and produces no output', async () => {
    const processor = makeProcessor('skipped', [], async (_ctx, _cfg) => {
      return { output: { custom: { ran: true } } };
    });

    const config = makeConfig('skipped', 10, [], {
      condition: async (_ctx) => false,
    });

    const { pipeline } = makePipeline([processor], [config]);
    const result = await pipeline.execute({ content: 'hello' });

    expect(result.processorsRun).not.toContain('skipped');
    expect(result.skippedProcessors).toContain('skipped');
    expect(result.outputs).toBeUndefined(); // outputs not in PipelineExecutionResult, but processor didn't run
  });

  it('dependent processor fails if required dependency is skipped', async () => {
    // A is skipped, B depends on A and has no condition -> B should fail with error
    const processorA = makeProcessor('A', [], async () => ({ output: {} }));
    const processorB = makeProcessor('B', ['A'], async () => ({ output: {} }));

    const configs: ProcessorRuntimeConfig[] = [
      makeConfig('A', 10, [], { condition: async () => false }),
      makeConfig('B', 20, ['A']), // no condition
    ];

    const { pipeline } = makePipeline([processorA, processorB], configs);
    const result = await pipeline.execute({ content: 'hello' });

    expect(result.skippedProcessors).toContain('A');
    expect(result.processorsRun).not.toContain('B');
    expect(result.errors.some((e) => e.includes('B'))).toBe(true);
  });

  it('async conditions are properly awaited', async () => {
    let conditionResolved = false;
    const processor = makeProcessor('async-cond', [], async () => ({
      output: { custom: { ran: true } },
    }));

    const config = makeConfig('async-cond', 10, [], {
      condition: async (_ctx) => {
        await new Promise((resolve) => setTimeout(resolve, 10));
        conditionResolved = true;
        return true;
      },
    });

    const { pipeline } = makePipeline([processor], [config]);
    const result = await pipeline.execute({ content: 'test' });

    expect(conditionResolved).toBe(true);
    expect(result.processorsRun).toContain('async-cond');
  });

  it('result includes all skipped processor IDs', async () => {
    const pA = makeProcessor('A', [], async () => ({ output: {} }));
    const pB = makeProcessor('B', [], async () => ({ output: {} }));
    const pC = makeProcessor('C', [], async () => ({ output: {} }));

    const configs: ProcessorRuntimeConfig[] = [
      makeConfig('A', 10, [], { condition: async () => false }),
      makeConfig('B', 20, [], { condition: async () => false }),
      makeConfig('C', 30, []),
    ];

    const { pipeline } = makePipeline([pA, pB, pC], configs);
    const result = await pipeline.execute({ content: 'test' });

    expect(result.skippedProcessors).toContain('A');
    expect(result.skippedProcessors).toContain('B');
    expect(result.skippedProcessors).not.toContain('C');
    expect(result.processorsRun).toContain('C');
  });
});

// ─── OUTPUT TRANSFORMATION TESTS ─────────────────────────────────────────────

describe('Output Transformation', () => {
  it('processor output is transformed before being stored in context.outputs', async () => {
    let seenOutput: unknown;

    const processorA = makeProcessor('A', [], async () => ({
      output: { custom: { value: 'original' } },
    }));

    const processorB = makeProcessor('B', ['A'], async (ctx, _cfg) => {
      seenOutput = ctx.outputs['A'];
      return { output: {} };
    });

    const configs: ProcessorRuntimeConfig[] = [
      makeConfig('A', 10, [], {
        outputTransform: async (output, _ctx) => {
          // Transform: change value to 'transformed'
          return { custom: { value: 'transformed' } };
        },
      }),
      makeConfig('B', 20, ['A']),
    ];

    const { pipeline } = makePipeline([processorA, processorB], configs);
    await pipeline.execute({ content: 'test' });

    expect(seenOutput).toEqual({ custom: { value: 'transformed' } });
  });

  it('downstream processor receives transformed output, not original', async () => {
    let downstreamSawOutput: unknown;

    const processorA = makeProcessor('upstream', [], async () => ({
      output: { custom: { data: 'raw' } },
    }));

    const processorB = makeProcessor('downstream', ['upstream'], async (ctx, _cfg) => {
      downstreamSawOutput = ctx.outputs['upstream'];
      return { output: {} };
    });

    const configs: ProcessorRuntimeConfig[] = [
      makeConfig('upstream', 10, [], {
        outputTransform: (_output, _ctx) => ({ custom: { data: 'processed' } }),
      }),
      makeConfig('downstream', 20, ['upstream']),
    ];

    const { pipeline } = makePipeline([processorA, processorB], configs);
    await pipeline.execute({ content: 'hello world' });

    expect(downstreamSawOutput).toEqual({ custom: { data: 'processed' } });
    expect((downstreamSawOutput as any)?.custom?.data).toBe('processed');
  });

  it('async transformations are properly awaited', async () => {
    let transformCompleted = false;
    let seenOutput: unknown;

    const processorA = makeProcessor('tx-async', [], async () => ({
      output: { custom: { num: 1 } },
    }));

    const processorB = makeProcessor('tx-consumer', ['tx-async'], async (ctx, _cfg) => {
      seenOutput = ctx.outputs['tx-async'];
      return { output: {} };
    });

    const configs: ProcessorRuntimeConfig[] = [
      makeConfig('tx-async', 10, [], {
        outputTransform: async (output, _ctx) => {
          await new Promise((resolve) => setTimeout(resolve, 10));
          transformCompleted = true;
          return { custom: { num: 99 } };
        },
      }),
      makeConfig('tx-consumer', 20, ['tx-async']),
    ];

    const { pipeline } = makePipeline([processorA, processorB], configs);
    await pipeline.execute({ content: 'test' });

    expect(transformCompleted).toBe(true);
    expect(seenOutput).toEqual({ custom: { num: 99 } });
  });

  it('multiple processors with transformations chain correctly', async () => {
    const seenByC: Record<string, unknown> = {};

    const processorA = makeProcessor('chainA', [], async () => ({
      output: { custom: { val: 'a-original' } },
    }));

    const processorB = makeProcessor('chainB', [], async () => ({
      output: { custom: { val: 'b-original' } },
    }));

    const processorC = makeProcessor('chainC', ['chainA', 'chainB'], async (ctx, _cfg) => {
      seenByC['chainA'] = ctx.outputs['chainA'];
      seenByC['chainB'] = ctx.outputs['chainB'];
      return { output: {} };
    });

    const configs: ProcessorRuntimeConfig[] = [
      makeConfig('chainA', 10, [], {
        outputTransform: (_o, _ctx) => ({ custom: { val: 'a-transformed' } }),
      }),
      makeConfig('chainB', 20, [], {
        outputTransform: (_o, _ctx) => ({ custom: { val: 'b-transformed' } }),
      }),
      makeConfig('chainC', 30, ['chainA', 'chainB']),
    ];

    const { pipeline } = makePipeline([processorA, processorB, processorC], configs);
    await pipeline.execute({ content: 'test' });

    expect(seenByC['chainA']).toEqual({ custom: { val: 'a-transformed' } });
    expect(seenByC['chainB']).toEqual({ custom: { val: 'b-transformed' } });
  });
});

// ─── RUNTIME REGISTRATION TESTS ──────────────────────────────────────────────

describe('Runtime Processor Registration', () => {
  it('processor can register a new processor mid-execution', async () => {
    const dynamicRan: string[] = [];

    const dynamicProcessor = makeProcessor('dynamic', [], async (_ctx, _cfg) => {
      dynamicRan.push('dynamic');
      return { output: {} };
    });

    const processorA = makeProcessor('registrar', [], async (ctx, _cfg) => {
      // Register a new processor during execution
      ctx.registerProcessor!(dynamicProcessor, makeConfig('dynamic', 99, []));
      return { output: {} };
    });

    const { pipeline } = makePipeline([processorA], [makeConfig('registrar', 10, [])]);
    const result = await pipeline.execute({ content: 'test' });

    expect(result.processorsRun).toContain('registrar');
    expect(result.processorsRun).toContain('dynamic');
    expect(dynamicRan).toContain('dynamic');
  });

  it('dynamically registered processor is topologically sorted with existing processors', async () => {
    const executionOrder: string[] = [];

    const processorB = makeProcessor('B', [], async (_ctx, _cfg) => {
      executionOrder.push('B');
      return { output: {} };
    });

    // Dynamic D depends on B - so D must run after B
    const processorD = makeProcessor('D', ['B'], async (_ctx, _cfg) => {
      executionOrder.push('D');
      return { output: {} };
    });

    const processorA = makeProcessor('A', [], async (ctx, _cfg) => {
      executionOrder.push('A');
      // Register D which depends on B
      ctx.registerProcessor!(processorD, makeConfig('D', 99, ['B']));
      return { output: {} };
    });

    // B has higher order (runs later normally), but D depends on B
    const configs: ProcessorRuntimeConfig[] = [
      makeConfig('A', 10, []),
      makeConfig('B', 20, []),
    ];

    const { pipeline } = makePipeline([processorA, processorB], configs);
    const result = await pipeline.execute({ content: 'test' });

    // D must come after B in execution
    expect(result.processorsRun).toContain('D');
    const bIdx = result.processorsRun.indexOf('B');
    const dIdx = result.processorsRun.indexOf('D');
    expect(bIdx).toBeLessThan(dIdx);
  });

  it('dynamically registered processor executes and produces output', async () => {
    const dynamicProcessor = makeProcessor('dynProc', [], async (_ctx, _cfg) => {
      return { output: { custom: { dynamicOutput: 'hello from dynamic' } } };
    });

    const processorA = makeProcessor('trigger', [], async (ctx, _cfg) => {
      ctx.registerProcessor!(dynamicProcessor, makeConfig('dynProc', 99, []));
      return { output: {} };
    });

    const { pipeline } = makePipeline([processorA], [makeConfig('trigger', 10, [])]);
    const result = await pipeline.execute({ content: 'test' });

    expect(result.processorsRun).toContain('dynProc');
    // The dynamic processor ran and produced output merged into result
    expect(result.result.custom).toEqual({ dynamicOutput: 'hello from dynamic' });
  });

  it('result includes all dynamically registered processor IDs', async () => {
    const dynP1 = makeProcessor('dyn1', [], async () => ({ output: {} }));
    const dynP2 = makeProcessor('dyn2', [], async () => ({ output: {} }));

    const processorA = makeProcessor('A', [], async (ctx, _cfg) => {
      ctx.registerProcessor!(dynP1, makeConfig('dyn1', 90, []));
      ctx.registerProcessor!(dynP2, makeConfig('dyn2', 91, []));
      return { output: {} };
    });

    const { pipeline } = makePipeline([processorA], [makeConfig('A', 10, [])]);
    const result = await pipeline.execute({ content: 'test' });

    expect(result.dynamicProcessors).toContain('dyn1');
    expect(result.dynamicProcessors).toContain('dyn2');
  });
});

// ─── INTEGRATION & REGRESSION TESTS ──────────────────────────────────────────

describe('Integration & Regression', () => {
  it('complex pipeline with conditionals, registrations, and transforms executes correctly', async () => {
    const executionOrder: string[] = [];
    const seenContextOutputs: Record<string, unknown> = {};

    // Processor A: always runs, produces output, transformed
    const processorA = makeProcessor('A', [], async (_ctx, _cfg) => {
      executionOrder.push('A');
      return { output: { custom: { from: 'A', val: 10 } } };
    });

    // Processor B: conditionally runs (condition: A's output val > 5)
    const processorB = makeProcessor('B', ['A'], async (ctx, _cfg) => {
      executionOrder.push('B');
      seenContextOutputs['A'] = ctx.outputs['A'];
      return { output: { custom: { from: 'B' } } };
    });

    // Dynamic processor registered by B
    const processorDyn = makeProcessor('Dyn', [], async (ctx, _cfg) => {
      executionOrder.push('Dyn');
      return { output: { custom: { from: 'Dyn' } } };
    });

    // Processor C: depends on B, has no condition
    const processorC = makeProcessor('C', ['B'], async (_ctx, _cfg) => {
      executionOrder.push('C');
      return { output: {} };
    });

    const configs: ProcessorRuntimeConfig[] = [
      makeConfig('A', 10, [], {
        outputTransform: (output, _ctx) => {
          const o = output as { custom: { from: string; val: number } };
          return { custom: { from: o.custom.from, val: o.custom.val * 2 } }; // val becomes 20
        },
      }),
      makeConfig('B', 20, ['A'], {
        condition: async (ctx) => {
          const aOut = ctx.outputs['A'] as { custom: { val: number } } | undefined;
          return (aOut?.custom?.val ?? 0) > 5;
        },
      }),
      makeConfig('C', 30, ['B']),
    ];

    // Note: B also registers Dyn during execution - but we need B to have access to registerProcessor
    // Let's add Dyn registration to B's process function
    const processorBWithReg = makeProcessor('B', ['A'], async (ctx, _cfg) => {
      executionOrder.push('B');
      seenContextOutputs['A'] = ctx.outputs['A'];
      ctx.registerProcessor!(processorDyn, makeConfig('Dyn', 25, []));
      return { output: { custom: { from: 'B' } } };
    });

    const { pipeline } = makePipeline(
      [processorA, processorBWithReg, processorC],
      configs,
    );
    const result = await pipeline.execute({ content: 'integration test' });

    // A should have run
    expect(executionOrder).toContain('A');
    // B's condition checks A's output which is transformed to val=20 > 5 -> B runs
    expect(executionOrder).toContain('B');
    // C depends on B which ran -> C should run
    expect(executionOrder).toContain('C');
    // Dyn was registered by B and should run
    expect(executionOrder).toContain('Dyn');
    // A's output seen by B should be the transformed value
    expect((seenContextOutputs['A'] as any)?.custom?.val).toBe(20);
    // Result should include dynamic processors
    expect(result.dynamicProcessors).toContain('Dyn');
  });

  it('original dependency ordering behavior is preserved when no new features are used', async () => {
    // No conditions, no transforms, no dynamic registration
    const pA = makeProcessor('plain-A', [], async () => ({ output: {} }));
    const pB = makeProcessor('plain-B', [], async () => ({ output: {} }));
    const pC = makeProcessor('plain-C', [], async () => ({ output: {} }));

    const configs: ProcessorRuntimeConfig[] = [
      makeConfig('plain-A', 10, []),
      makeConfig('plain-B', 20, []),
      makeConfig('plain-C', 30, []),
    ];

    const { pipeline } = makePipeline([pA, pB, pC], configs);
    const result = await pipeline.execute({ content: 'test content' });

    expect(result.processorsRun).toEqual(['plain-A', 'plain-B', 'plain-C']);
    expect(result.errors).toHaveLength(0);
    expect(result.skippedProcessors).toHaveLength(0);
    expect(result.dynamicProcessors).toHaveLength(0);
  });

  it('output isolation prevents processors from overwriting each other', async () => {
    const capturedOutputs: Record<string, unknown>[] = [];

    const processorA = makeProcessor('iso-A', [], async () => ({
      output: { custom: { ownerA: 'valueA', shared: 'from-A' } },
    }));

    const processorB = makeProcessor('iso-B', [], async (ctx, _cfg) => {
      capturedOutputs.push({ ...ctx.outputs });
      return { output: { custom: { ownerB: 'valueB', shared: 'from-B' } } };
    });

    const processorC = makeProcessor('iso-C', ['iso-A', 'iso-B'], async (ctx, _cfg) => {
      capturedOutputs.push({ ...ctx.outputs });
      return { output: {} };
    });

    const configs: ProcessorRuntimeConfig[] = [
      makeConfig('iso-A', 10, []),
      makeConfig('iso-B', 20, []),
      makeConfig('iso-C', 30, ['iso-A', 'iso-B']),
    ];

    const { pipeline } = makePipeline([processorA, processorB, processorC], configs);
    await pipeline.execute({ content: 'isolation test' });

    // When C runs, it should see both iso-A and iso-B outputs
    const cOutputs = capturedOutputs[1];
    expect(cOutputs['iso-A']).toBeDefined();
    expect(cOutputs['iso-B']).toBeDefined();
    // Each processor's output is stored under its own key
    expect((cOutputs['iso-A'] as any)?.custom?.ownerA).toBe('valueA');
    expect((cOutputs['iso-B'] as any)?.custom?.ownerB).toBe('valueB');
  });

  it('processor errors are caught and reported correctly', async () => {
    const throwingProcessor = makeProcessor('thrower', [], async () => {
      throw new Error('Something went wrong');
    });

    const afterProcessor = makeProcessor('after', [], async () => ({
      output: { custom: { afterRan: true } },
    }));

    const configs: ProcessorRuntimeConfig[] = [
      makeConfig('thrower', 10, []),
      makeConfig('after', 20, []),
    ];

    const { pipeline } = makePipeline([throwingProcessor, afterProcessor], configs);
    const result = await pipeline.execute({ content: 'test' });

    expect(result.errors.some((e) => e.includes('thrower') && e.includes('Something went wrong'))).toBe(true);
    // After processor should still run
    expect(result.processorsRun).toContain('after');
    expect(result.result.custom).toEqual({ afterRan: true });
  });
});
EOF"}

