    expect(executionOrder).toContain('B');
    // C depends on B which ran -> C should run
    expect(executionOrder).toContain('C');
    // Dyn was registered by B and should run
    expect(executionOrder).toContain('Dyn');
    // A's output seen by B should be the transformed value
    expect((seenContextOutputs['A'] as any)?.custom?.val).toBe(20);
