import { StructuredLogger } from '../metrics/logger';
import { Processor, ProcessorOverride, ProcessorRuntimeConfig } from '../types';

export interface ResolvedProcessor {
  processor: Processor;
  config: ProcessorRuntimeConfig;
}

export class ProcessorRegistry {
  private readonly processors = new Map<string, Processor>();
  private readonly runtimeConfigs = new Map<string, ProcessorRuntimeConfig>();

  constructor(processors: Processor[], private readonly logger: StructuredLogger) {
    for (const processor of processors) {
      this.processors.set(processor.definition.id, processor);
    }
  }

  getRegisteredIds() {
    return Array.from(this.processors.keys());
  }

  loadRuntimeConfigs(configs: ProcessorRuntimeConfig[]) {
    this.runtimeConfigs.clear();
    for (const config of configs) {
      this.runtimeConfigs.set(config.id, { ...config });
    }
    this.logger.info('processor-configs-loaded', { count: configs.length });
  }

  listProcessors() {
    return Array.from(this.processors.values())
      .sort((left, right) => left.definition.id.localeCompare(right.definition.id))
      .map((processor) => ({
        definition: processor.definition,
        runtimeConfig: this.runtimeConfigs.get(processor.definition.id) ?? null,
      }));
  }

  getRuntimeConfigs() {
    return Array.from(this.runtimeConfigs.values()).sort((left, right) => left.order - right.order);
  }

  toggleProcessor(id: string, enabled: boolean) {
    const existing = this.runtimeConfigs.get(id);
    if (!existing) {
      throw new Error(`Unknown processor config: ${id}`);
    }

    const next = {
      ...existing,
      enabled,
    };

    this.runtimeConfigs.set(id, next);
    return next;
  }

  /**
   * Topologically sort the given resolved processors based on their dependencyIds.
   * Throws if there are circular dependencies, missing dependencies, or disabled dependencies.
   *
   * @param resolvedProcessors - Processors to sort (only enabled processors)
   * @param allConfigs - All known processor configs (enabled and disabled)
   * @param alreadyExecuted - Set of processor IDs that have already been executed (optional)
   *                          These are considered satisfied dependencies and won't cause errors.
   */
  static topologicalSort(
    resolvedProcessors: ResolvedProcessor[],
    allConfigs: Map<string, ProcessorRuntimeConfig>,
    alreadyExecuted: Set<string> = new Set(),
  ): ResolvedProcessor[] {
    const resolvedMap = new Map<string, ResolvedProcessor>();
    for (const rp of resolvedProcessors) {
      resolvedMap.set(rp.config.id, rp);
    }

    // Validate dependencies
    for (const rp of resolvedProcessors) {
      const deps = rp.config.dependencyIds ?? [];
      for (const depId of deps) {
        // Self-dependency check
        if (depId === rp.config.id) {
          throw new Error(`Processor "${rp.config.id}" has a self-dependency`);
        }
        // Check if the dependency exists in allConfigs
        if (!allConfigs.has(depId)) {
          throw new Error(`Processor "${rp.config.id}" depends on missing processor "${depId}"`);
        }
        // If the dependency has already been executed, it's satisfied - no error
        if (alreadyExecuted.has(depId)) {
          continue;
        }
        // Check if the dependency is disabled (not in resolvedMap and not already executed)
        const depConfig = allConfigs.get(depId)!;
        if (!depConfig.enabled || !resolvedMap.has(depId)) {
          throw new Error(`Processor "${rp.config.id}" depends on disabled processor "${depId}"`);
        }
      }
    }

    // Kahn's algorithm for topological sort
    // Only consider dependencies that are within the current resolved set
    // (not already-executed ones, which are already satisfied)
    const inDegree = new Map<string, number>();
    const adjacency = new Map<string, string[]>(); // depId -> dependents

    for (const rp of resolvedProcessors) {
      const id = rp.config.id;
      if (!inDegree.has(id)) inDegree.set(id, 0);
      if (!adjacency.has(id)) adjacency.set(id, []);

      const deps = rp.config.dependencyIds ?? [];
      for (const depId of deps) {
        // Skip already-executed dependencies - they don't affect ordering within this set
        if (alreadyExecuted.has(depId)) {
          continue;
        }
        // Only count dependencies that are within the current resolved set
        if (!resolvedMap.has(depId)) {
          continue;
        }
        const existing = adjacency.get(depId) ?? [];
        existing.push(id);
        adjacency.set(depId, existing);
        inDegree.set(id, (inDegree.get(id) ?? 0) + 1);
      }
    }

    // Start with nodes that have no unresolved dependencies (in-degree 0)
    // Among those, sort by order for deterministic ordering
    const queue: string[] = [];
    for (const [id, degree] of inDegree) {
      if (degree === 0) {
        queue.push(id);
      }
    }
    queue.sort((a, b) => {
      const orderA = resolvedMap.get(a)!.config.order;
      const orderB = resolvedMap.get(b)!.config.order;
      return orderA - orderB;
    });

    const sorted: ResolvedProcessor[] = [];
    while (queue.length > 0) {
      // Pick the first item (already sorted by order)
      const id = queue.shift()!;
      const rp = resolvedMap.get(id)!;
      sorted.push(rp);

      const dependents = adjacency.get(id) ?? [];
      const newlyZero: string[] = [];
      for (const depId of dependents) {
        const newDegree = (inDegree.get(depId) ?? 0) - 1;
        inDegree.set(depId, newDegree);
        if (newDegree === 0) {
          newlyZero.push(depId);
        }
      }
      // Sort newly zero by order before adding to queue
      newlyZero.sort((a, b) => {
        const orderA = resolvedMap.get(a)!.config.order;
        const orderB = resolvedMap.get(b)!.config.order;
        return orderA - orderB;
      });
      queue.push(...newlyZero);
    }

    if (sorted.length !== resolvedProcessors.length) {
      // There is a cycle
      const inCycle = resolvedProcessors
        .filter((rp) => !sorted.find((s) => s.config.id === rp.config.id))
        .map((rp) => rp.config.id);
      throw new Error(`Circular dependency detected among processors: ${inCycle.join(', ')}`);
    }

    return sorted;
  }

  resolve(overrides: Record<string, ProcessorOverride> = {}): ResolvedProcessor[] {
    const allConfigs = new Map<string, ProcessorRuntimeConfig>(this.runtimeConfigs);

    const resolved = this.getRuntimeConfigs()
      .map((config) => {
        const processor = this.processors.get(config.id);
        if (!processor) {
          return null;
        }

        const override = overrides[config.id];
        const resolvedConfig: ProcessorRuntimeConfig = {
          ...config,
          enabled: override?.enabled ?? config.enabled,
          options: {
            ...config.options,
            ...(override?.options ?? {}),
          },
        };

        return {
          processor,
          config: resolvedConfig,
        };
      })
      .filter((value): value is ResolvedProcessor => value !== null && value.config.enabled);

    // Apply topological sorting
    return ProcessorRegistry.topologicalSort(resolved, allConfigs);
  }
}
