import { createHash } from 'node:crypto';
import { MetricsCollector } from '../metrics/metrics';
import { StructuredLogger } from '../metrics/logger';
import { LruCache } from '../storage/cache';
import { PipelineExecutionResult, Processor, ProcessNoteRequest, ProcessingContext, ProcessingResult, ProcessorRuntimeConfig } from '../types';
import { ProcessorRegistry, ResolvedProcessor } from './registry';

function clone<T>(value: T): T {
  return JSON.parse(JSON.stringify(value)) as T;
}

function hashKey(input: string) {
  return createHash('sha256').update(input).digest('hex');
}

export class Pipeline {
  constructor(
    private readonly registry: ProcessorRegistry,
    private readonly cache: LruCache<string, PipelineExecutionResult>,
    private readonly metrics: MetricsCollector,
    private readonly logger: StructuredLogger,
  ) {}

  getCacheStats() {
    return this.cache.getStats();
  }

  clearCache() {
    this.cache.clear();
  }

  async execute(request: ProcessNoteRequest): Promise<PipelineExecutionResult> {
    const resolvedProcessors = this.registry.resolve(request.processorOverrides);
    const cacheKey = hashKey(JSON.stringify({
      content: request.content,
      overrides: request.processorOverrides ?? {},
      processors: resolvedProcessors.map((entry) => ({
        id: entry.config.id,
        enabled: entry.config.enabled,
        order: entry.config.order,
        options: entry.config.options,
      })),
    }));

    const cached = this.cache.get(cacheKey);
    if (cached) {
      return {
        ...clone(cached),
        cacheStatus: 'hit',
      };
    }

    const startedAt = new Date().toISOString();
    const result: ProcessingResult = {
      original: request.content,
      workingCopy: request.content,
    };

    const outputs: Record<string, unknown> = {};

    const context: ProcessingContext = {
      request,
      originalContent: request.content,
      workingContent: request.content,
      result,
      startedAt,
      outputs,
    };

    const errors: string[] = [];
    const warnings: string[] = [];
    const processorsRun: string[] = [];
    const skippedProcessors: string[] = [];
    const dynamicProcessors: string[] = [];

    // Dynamic processors registered during execution
    const pendingDynamicProcessors: Array<{ processor: Processor; config: ProcessorRuntimeConfig }> = [];

    // Set up the registerProcessor function on context
    context.registerProcessor = (processor: Processor, config: ProcessorRuntimeConfig) => {
      pendingDynamicProcessors.push({ processor, config });
    };

    // Track which processors have been skipped (for dependency checking)
    const skippedSet = new Set<string>();

    // Track which processors have already been executed (for topological sort of dynamic processors)
    const executedSet = new Set<string>();

    // We'll process in a queue to support dynamic registration
    const processorQueue: ResolvedProcessor[] = [...resolvedProcessors];

    // All processor configs seen so far (for topological sort of dynamic processors)
    const allConfigsSeen = new Map<string, ProcessorRuntimeConfig>();
    for (const rp of resolvedProcessors) {
      allConfigsSeen.set(rp.config.id, rp.config);
    }

    /**
     * Insert newly registered dynamic processors into the queue, re-sorting topologically.
     */
    const flushDynamicProcessors = (insertAtIndex: number) => {
      if (pendingDynamicProcessors.length === 0) return;

      const newDynamicProcessors = [...pendingDynamicProcessors];
      pendingDynamicProcessors.length = 0;

      for (const dp of newDynamicProcessors) {
        allConfigsSeen.set(dp.config.id, dp.config);
        dynamicProcessors.push(dp.config.id);
      }

      // Build the remaining queue + new dynamic processors and re-sort topologically
      const remaining = processorQueue.slice(insertAtIndex);
      const dynamicResolved: ResolvedProcessor[] = newDynamicProcessors.map((dp) => ({
        processor: dp.processor,
        config: dp.config,
      }));

      // Combine remaining + dynamic, re-sort
      const combined = [...remaining, ...dynamicResolved];
      try {
        const sorted = ProcessorRegistry.topologicalSort(combined, allConfigsSeen, executedSet);
        // Replace the remaining queue with the sorted result
        processorQueue.splice(insertAtIndex, processorQueue.length - insertAtIndex, ...sorted);
      } catch (err) {
        // If topological sort fails for dynamic processors, report error but keep remaining
        const message = err instanceof Error ? err.message : String(err);
        errors.push(`dynamic-registration: ${message}`);
        processorQueue.splice(insertAtIndex, processorQueue.length - insertAtIndex, ...remaining);
      }
    };

    let queueIndex = 0;
    while (queueIndex < processorQueue.length) {
      // Before processing this item, check if any dynamic processors have been registered
      flushDynamicProcessors(queueIndex);

      if (queueIndex >= processorQueue.length) break;

      const { processor, config } = processorQueue[queueIndex];
      queueIndex++;

      // Check if any dependency was skipped - if so, handle accordingly
      const deps = config.dependencyIds ?? [];
      let dependencySkipped = false;
      for (const depId of deps) {
        if (skippedSet.has(depId)) {
          dependencySkipped = true;
          break;
        }
      }

      if (dependencySkipped) {
        if (config.condition) {
          // Has a condition - skip it
          skippedProcessors.push(processor.definition.id);
          skippedSet.add(processor.definition.id);
          continue;
        } else {
          // No condition - fail with error
          const message = `Processor "${processor.definition.id}" depends on a skipped processor`;
          errors.push(`${config.id}: ${message}`);
          this.logger.error('processor-failed', {
            processorId: processor.definition.id,
            message,
          });
          continue;
        }
      }

      // Evaluate condition if present
      if (config.condition) {
        let conditionResult: boolean;
        try {
          conditionResult = await config.condition(context);
        } catch (err) {
          const message = err instanceof Error ? err.message : String(err);
          errors.push(`${config.id}: condition evaluation failed: ${message}`);
          skippedProcessors.push(processor.definition.id);
          skippedSet.add(processor.definition.id);
          continue;
        }

        if (!conditionResult) {
          skippedProcessors.push(processor.definition.id);
          skippedSet.add(processor.definition.id);
          continue;
        }
      }

      const validation = processor.validate(config);
      if (!validation.valid) {
        errors.push(...validation.errors.map((entry) => `${config.id}: ${entry.message}`));
        continue;
      }

      warnings.push(...validation.warnings.map((warning) => `${config.id}: ${warning}`));
      const runStarted = performance.now();

      try {
        const run = await processor.process(context, config);
        processorsRun.push(processor.definition.id);
        executedSet.add(processor.definition.id);

        // Compute raw output
        let rawOutput: unknown = run.output ?? {};

        // Apply output transform if present
        if (config.outputTransform) {
          rawOutput = await config.outputTransform(rawOutput, context);
        }

        // Store in outputs under the processor's ID
        outputs[processor.definition.id] = rawOutput;

        // Also merge into context.result for backwards compatibility
        if (rawOutput && typeof rawOutput === 'object') {
          Object.assign(context.result, rawOutput);
        }

        if (run.nextContent !== undefined) {
          context.workingContent = run.nextContent;
          context.result.workingCopy = run.nextContent;
        }
        if (run.errors) {
          errors.push(...run.errors.map((message) => `${config.id}: ${message}`));
        }
        if (run.warnings) {
          warnings.push(...run.warnings.map((message) => `${config.id}: ${message}`));
        }
        this.metrics.recordProcessorRun(processor.definition.id, performance.now() - runStarted, true);
      } catch (error) {
        this.metrics.recordProcessorRun(processor.definition.id, performance.now() - runStarted, false);
        const message = error instanceof Error ? error.message : String(error);
        errors.push(`${config.id}: ${message}`);
        context.lastError = error instanceof Error ? error : new Error(message);
        this.logger.error('processor-failed', {
          processorId: processor.definition.id,
          message,
        });
      }

      // After each processor, flush any newly registered dynamic processors
      flushDynamicProcessors(queueIndex);
    }

    const finishedAt = new Date().toISOString();
    const execution: PipelineExecutionResult = {
      cacheStatus: 'miss',
      processorsRun,
      result: clone(context.result),
      errors,
      warnings,
      startedAt,
      finishedAt,
      skippedProcessors: skippedProcessors.length > 0 ? skippedProcessors : [],
      dynamicProcessors: dynamicProcessors.length > 0 ? dynamicProcessors : [],
    };

    this.cache.set(cacheKey, clone(execution));
    return execution;
  }
}
EOF"}

